def range_summary(nums):
    if not nums:
        return ''

    sorted_nums = sorted(set(nums))
    ranges = []
    i = 0

    while i < len(sorted_nums):
        start = sorted_nums[i]
        while i + 1 < len(sorted_nums) and sorted_nums[i + 1] == sorted_nums[i] + 1:
            i += 1
        end = sorted_nums[i]
        if start == end:
            ranges.append(str(start))
        else:
            ranges.append(f'{start}-{end}')
        i += 1

    return ','.join(ranges)
